import React, { useEffect, useRef } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';

const Scanner = ({ onScanSuccess }) => {
  const scannerRef = useRef(null);

  useEffect(() => {
    // 1. Create the scanner instance
    const scanner = new Html5QrcodeScanner('reader', {
      fps: 10,
      qrbox: { width: 250, height: 250 },
      aspectRatio: 1.0
    });

    // 2. Render the scanner
    scanner.render(
      (decodedText) => {
        onScanSuccess(decodedText);
        // We don't clear here, we let the parent close the component
      },
      (error) => {
        // Just ignore errors while searching for a code
      }
    );

    // 3. CLEANUP: This is the most important part
    // This runs when the component "dies" or restarts
    return () => {
      scanner.clear().catch((error) => {
        console.error("Failed to clear scanner on unmount", error);
      });
    };
  }, []); // Empty array means "only run once on start"

  return (
    <div style={{ 
      maxWidth: '500px', 
      margin: '20px auto', 
      border: '2px solid #00d1b2', 
      borderRadius: '10px', 
      overflow: 'hidden',
      background: '#fff' 
    }}>
      <div id="reader"></div>
    </div>
  );
};

export default Scanner;
